class Box<T> {
  private T item;

  public void setItem(T item) {
    this.item = item;
  }

  public T getItem() {
    return item;
  }
}

public class Main {
  public static void main(String[] args) {
    Box<String> stringBox = new Box<>();
    stringBox.setItem("Kitab");
    System.out.println("Qutuda: " + stringBox.getItem());

    Box<Integer> intBox = new Box<>();
    intBox.setItem(42);
    System.out.println("Qutuda: " + intBox.getItem());
  }
}
// Çıxış:
// Qutuda: Kitab
// Qutuda: 42

import java.util.ArrayList;

public class Main {
  public static <T> void printList(ArrayList<T> list) {
    for (T item : list) {
      System.out.println("Element: " + item);
    }
  }

  public static void main(String[] args) {
    ArrayList<String> stringList = new ArrayList<>();
    stringList.add("Alma");
    stringList.add("Armud");
    printList(stringList);

    ArrayList<Integer> intList = new ArrayList<>();
    intList.add(1);
    intList.add(2);
    printList(intList);
  }
}
// Çıxış:
// Element: Alma
// Element: Armud
// Element: 1
// Element: 2

