class Pair<K, V> {
  private K key;
  private V value;

  public Pair(K key, V value) {
    this.key = key;
    this.value = value;
  }

  public String toString() {
    return key + ": " + value;
  }
}

public class Main {
  public static void main(String[] args) {
    Pair<String, Integer> pair = new Pair<>("Yaş", 25);
    System.out.println("Cüt: " + pair);
  }
}
// Çıxış: Cüt: Yaş: 25

